import hashlib
import itertools

def hash_password(password):
    """Hashes a password using SHA-256."""
    return hashlib.sha256(password.encode()).hexdigest()

def generate_rainbow_table(wordlist, max_length=8):
    """Generates a rainbow table from a wordlist."""
    rainbow_table = {}
    for word in wordlist:
        # Generate all combinations of the word up to max_length
        for length in range(1, max_length + 1):
